INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 1, 1, "2023/06/30 12:00:00", 1.47, "2023/09/22 14:59:59", 126401, "クローチェ", 10001, 2002, 0.0, "いらっしゃいませっ♪\nキャラバンコインを使って\n買い物ができますよっ！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 1, 2, "2023/06/30 12:00:00", 2.15, "2023/09/22 14:59:59", 126401, "クローチェ", 10002, 2002, 0.0, "素敵な品が揃ってるので\nたーっくさん買っていって\nくださいねっ♪");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 1, 2, "2023/06/30 12:00:00", 0.0, "2023/09/22 14:59:59", 126501, "ライラエル", 10003, 2002, 0.0, "ショップへようこそ\nキャラバンコインはこちら\nで買い物に使えますよ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 1, 1, "2023/06/30 12:00:00", 0.0, "2023/09/22 14:59:59", 126501, "ライラエル", 10004, 2002, 0.0, "こちらのショップで\n買い物をして、素敵な\n旅を楽しんでくださいね");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 2, 2, "2023/09/15 15:00:00", 0.0, "2023/12/22 14:59:59", 127702, "リンド", 10005, 2002, 0.0, "いらっしゃいませ\nキャラバンコインを使って\nお買い物ができますよ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 2, 2, 2, "2023/09/15 15:00:00", 0.0, "2023/12/22 14:59:59", 127702, "リンド", 10006, 2002, 0.0, "ショップの掃除は完璧です\n姫さま直営のお店として\n当然のことですから");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 2, 1, "2023/09/15 15:00:00", 0.0, "2023/12/22 14:59:59", 127802, "ヴルム", 10007, 2002, 0.0, "ショップへようこそ\nキャラバンコインと品物を\n交換できるんで、よければ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 2, 2, "2023/09/15 15:00:00", 6.5, "2023/12/22 14:59:59", 127802, "ヴルム", 10008, 2002, 0.0, "なんで店番なんか…\nま、やりますけど\n好きな品物をどうぞ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 3, 2, "2023/12/15 15:00:00", 0.0, "2024/03/22 14:59:59", 129602, "アネモネ", 10009, 2002, 0.0, "──いらっしゃいませ\n買い物しても、いいですよ\nキャラバンコインがあれば");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 3, 2, "2023/12/15 15:00:00", 0.0, "2024/03/22 14:59:59", 129602, "アネモネ", 10010, 2002, 0.0, "──もっと笑顔がほしい？\nいくらコインを積まれても\n売れない物はありますから");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 3, 1, "2023/12/15 15:00:00", 0.0, "2024/03/22 14:59:59", 129701, "ネフィ=ネラ", 10011, 2002, 0.0, "ようこそおいでなんし\nキャラバンコインをこちら\nで交換して進ぜんしょう");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 3, 2, "2023/12/15 15:00:00", 6.2, "2024/03/22 14:59:59", 129701, "ネフィ=ネラ", 10012, 2002, 0.0, "ところで、お前さまは\nいくらで贖えるのか喃？\n──フフ、冗談でありんす");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 5, 4, 3, "2024/03/15 15:00:00", 3.1, "2024/06/22 14:59:59", 130301, "カノン", 10013, 2002, 0.0, "い、いらっしゃいませっ！\n…くっ…このあたくし様が\n店番なんて…屈辱ですわっ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 2, 4, 3, "2024/03/15 15:00:00", 6.15, "2024/06/22 14:59:59", 130301, "カノン", 10014, 2002, 0.0, "あら、あたくしをご所望？\nお生憎様、そんな小銭では\n…買えちゃうんですの！？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 4, 2, "2024/03/15 15:00:00", 0.0, "2024/06/22 14:59:59", 130401, "ナーナ", 10015, 2002, 0.0, "いらっしゃいませ～♪\nきゃらばんこいん？を\n交換できるんだってー");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 4, 2, "2024/03/15 15:00:00", 3.35, "2024/06/22 14:59:59", 130401, "ナーナ", 10016, 2002, 0.0, "甘いのくれたら、\nお礼にナーナの拾った\n松ぼっくりあげちゃうよ！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 5, 1, "2024/06/15 15:00:00", 0.0, "2024/09/22 14:59:59", 130502, "ホウオウ", 10017, 2002, 0.0, "ショップへようこそ\nこの鳳凰が、皆さんに\n祝福を差し上げましょう");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 5, 2, "2024/06/15 15:00:00", 3.18, "2024/09/22 14:59:59", 130502, "ホウオウ", 10018, 2002, 0.0, "ほーちゃんと呼ぶ権利は\n売っていませんよ？\n騎士さんへの、特別です！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 3, 4, 5, 4, "2024/06/15 15:00:00", 0.0, "2024/09/22 14:59:59", 130503, "ホウオウ", 10019, 2002, 0.0, "うﾞぇぇえんっ！まﾞだごの\n格好になっぢゃいまじだ！\n寄付をお願いじまず～っ！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 5, 1, "2024/06/15 15:00:00", 4.9, "2024/09/22 14:59:59", 123301, "ネア", 10020, 2002, 0.0, "おっすー♪\nなんでも交換してけー\nカリザきゅん以外で");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 2, 5, 1, "2024/06/15 15:00:00", 4.8, "2024/09/22 14:59:59", 123301, "ネア", 10021, 2002, 0.0, "ところで、騎士きゅんは\nおいくら万ルピ？\nジョーダンぬ・き・で♡");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 6, 3, "2024/09/15 15:00:00", 4.922, "2024/12/22 14:59:59", 133301, "カリザ", 10022, 2002, 0.0, "ケッ、なんでオレ様が店番\nなんざ…って来んなキイロ\nオレは売りモンじゃねー！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 5, 6, 3, "2024/09/15 15:00:00", 9.638, "2024/12/22 14:59:59", 133301, "カリザ", 10023, 2002, 0.0, "い、言わなきゃダメか？\n「…いらっしゃいませ…」\nクソッ、笑うんじゃねー！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 6, 1, "2024/09/15 15:00:00", 2.88, "2024/12/22 14:59:59", 133401, "ミーア", 10024, 2002, 0.0, "ショップへようこそ～\nネラさまの腹心…的な私が\n店番させていただきま～す");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 6, 5, "2024/09/15 15:00:00", 4.818, "2024/12/22 14:59:59", 133401, "ミーア", 10025, 2002, 0.0, "私の抜け殻とか、\n需要ありますかね～…\nって冗談ですよ、冗談！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 7, 2, "2024/12/15 15:00:00", 1.78, "2025/03/22 14:59:59", 133002, "グレイス", 10026, 2002, 0.0, "へい、らっしゃい\nさ、騎士氏。冥土の土産は\nなにがいいですか？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 7, 7, 1, "2024/12/15 15:00:00", 6.15, "2025/03/22 14:59:59", 133002, "グレイス", 10027, 2002, 0.0, "商品をお買い上げ毎に\nグレイスちゃんポイントを\n差し上げます。嘘ですが");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 7, 6, "2024/12/15 15:00:00", 4.28, "2025/03/22 14:59:59", 133102, "ヴァイオレット", 10028, 2002, 0.0, "ようこそいらっしゃいませ\n…接客とは、このような\n振舞で宜しいでしょうか？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 7, 1, "2024/12/15 15:00:00", 0.0, "2025/03/22 14:59:59", 133102, "ヴァイオレット", 10029, 2002, 0.0, "じめじめした商品は\nございませんので\n安心してお買い求め下さい");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 8, 2, "2025/03/15 15:00:00", 5.53, "2025/06/23 14:59:59", 136902, "ルルィ", 10030, 2002, 0.0, "いらっしゃいましぇでしゅ\n何をお求めでしゅか？\nたこ焼きもありましゅよ！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 7, 8, 9, "2025/03/15 15:00:00", 6.05, "2025/06/23 14:59:59", 136902, "ルルィ", 10031, 2002, 0.0, "そのコイン…ピカピカで、\n集めたくなっちゃいましゅ\nタコ釣られされちゃう～…");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 8, 2, "2025/03/15 15:00:00", 0.0, "2025/06/23 14:59:59", 137001, "デュラン", 10032, 2002, 0.0, "姫のご友人ならば\n礼儀を尽くすのが爺の務め\nさ、望みの物を言いたまえ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 8, 2, "2025/03/15 15:00:00", 0.0, "2025/06/23 14:59:59", 137001, "デュラン", 10033, 2002, 0.0, "キャラバンコインではなく\n首で支払って貰えんかのぅ\n…冗談であるぞ？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 9, 2, "2025/06/16 15:00:00", 0.0, "2025/09/23 14:59:59", 135902, "サツキ", 10034, 2002, 0.0, "おう\n好きなもん持ってきな");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 6, 9, 1, "2025/06/16 15:00:00", 4.935, "2025/09/23 14:59:59", 135902, "サツキ", 10035, 2002, 0.0, "宵越しの銭を持つような\n野暮いマネぁしくさんな\nツキが落ちてもしらねぇぜ");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 5, 9, 2, "2025/06/16 15:00:00", 7.441, "2025/09/23 14:59:59", 135802, "ユキノ", 10036, 2002, 0.0, "ら、ら、らっしゃっせ…\nなんかほしいもん、ある？\nか、かき氷とか、ど…？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 7, 9, 7, "2025/06/16 15:00:00", 0.0, "2025/09/23 14:59:59", 135802, "ユキノ", 10037, 2002, 0.0, "そ、そんな見ねぇで…\nあては、売りもんじゃ\nねぇよ…？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 2, 10, 2, "2025/09/16 15:00:00", 2.295, "2025/12/22 14:59:59", 130901, "クルル", 10038, 2002, 0.0, "クルルをお求めですかっ？\nそれならお礼に、こちらの\n宝石もどうぞですよ～♪");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 6, 10, 1, "2025/09/16 15:00:00", 6.281, "2025/12/22 14:59:59", 130901, "クルル", 10039, 2002, 0.0, "はっ！　ヒーローさんから\nお代なんて頂けないです！\nどうぞどうぞ…え、ダメ？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 10, 2, "2025/09/16 15:00:00", 5.549, "2025/12/22 14:59:59", 137701, "ヴォルガーノ", 10040, 2002, 0.0, "よぅ！　今日の俺さまは\n門番じゃなく、店番だぜ\nメモピ～スフィア～てな！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 6, 10, 3, "2025/09/16 15:00:00", 2.64, "2025/12/22 14:59:59", 137701, "ヴォルガーノ", 10041, 2002, 0.0, "…リマさんのブロマイド？\n買い取るに決まってらぁ！\nなんでも持ってけ泥棒っ！");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 4, 11, 7, "2025/12/15 15:00:00", 7.642, "2026/03/23 11:59:59", 132801, "ライラエル", 10042, 2002, 0.0, "こ、この格好は…ヴルムが\n集客効果があると言って…\n…本当でしょうか？");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 11, 1, "2025/12/15 15:00:00", 0.0, "2026/03/23 11:59:59", 132802, "ライラエル", 10043, 2002, 0.0, "この我に店番させるとは…\n全て買わねば許さぬぞ\n我が国庫に貢献するが良い");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 1, 1, 11, 1, "2025/12/15 15:00:00", 0.0, "2026/03/23 11:59:59", 134502, "クローチェ", 10044, 2002, 0.0, "アナライズっ！\n本日のオススメ商品は～…\nこちらですっ♪");
INSERT INTO `v1_5b9d75c11bd3bf5f1866c32ff9319da290fec932b6ad0e17a13eaaccdc5d7daf` VALUES (-470.0, 2, 1, 11, 2, "2025/12/15 15:00:00", 3.72, "2026/03/23 11:59:59", 134501, "クローチェ", 10045, 2002, 0.0, "ギガンティックローチェ、\nおひとついかがですかっ？\n格納庫用意して下さいねっ");
